import React, { useEffect, useState } from "react";
import { NavLink } from "react-router-dom";
import Container from "react-bootstrap/Container";
import Row from "react-bootstrap/Row";
import Col from "react-bootstrap/Col";
import Button from 'react-bootstrap/Button';
import {X,Filter,Person,Check,ViewStacked,CalendarWeek,PersonBoundingBox,BarChartSteps, XCircle,Download,PlusLg,CheckCircle} from "react-bootstrap-icons";
import SearchFilter from './SearchFilter';
import User01 from "../../../../assets/images/icon/user-01.png";
import Tab from 'react-bootstrap/Tab';
import Tabs from 'react-bootstrap/Tabs';


const TableTopBar = ({rows,onRowsFilterChange, salesData, selectedRowCount,selectClass,selectedRow }) => {
  const [totalAmount, setTotalAmount] = useState(0);
  const [selectedItems, setSelectedItems] = useState([]);
  const [buttonClicked, setButtonClicked] = useState(false);
  const [filteredItems, setFilteredItems] = useState([]);

  const formattedAmount = totalAmount.toLocaleString("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });

  useEffect(() => {
    if (salesData) {
      const calculatedTotalAmount = salesData.reduce(
        (total, sale) => total + sale.amount,
        0
      );
      setTotalAmount(calculatedTotalAmount);
    }
  }, [salesData]);



  const fullNames = [...new Set(salesData.map(item => item.manager.full_name))];
  const createdDate = [...new Set(salesData.map(item => item.created))];
  const statuses = Array.from(new Set(salesData.map(item => item.status)));
  const clientNames = Array.from(new Set(salesData.map(item => item.client.name)));
  const userNames = Array.from(new Set(salesData.map(item => item.manager.alias_name)));
  const lead = Array.from(new Set(salesData.map(item => item.lead.name)));
  const percentage = Array.from(new Set(salesData.map(item => item.lead.percentage)));
  

  const getStatusCount = (status) => {
    return salesData.filter(item => item.status === status).length;
  };

  const createdDateJson = JSON.stringify(createdDate, null, 2);
  const fullNamesJson = JSON.stringify(fullNames, null, 2);
  const statusesJson = JSON.stringify(statuses, null, 2);
  const leadJson = JSON.stringify(lead, null, 2);
  const percentageJson = JSON.stringify(percentage, null, 2);
  const createdDateArray = JSON.parse(createdDateJson);
  const fullNamesArray = JSON.parse(fullNamesJson);
  const StatusesArray = JSON.parse(statusesJson);
  const clientNamesJson = JSON.stringify(clientNames, null, 2);
  const ClientNamesArray = JSON.parse(clientNamesJson);
  const userNamesJson = JSON.stringify(userNames, null, 2);
  const UserNamesArray = JSON.parse(userNamesJson);
  const leadArray = JSON.parse(leadJson);
  const percentageJsonArray = JSON.parse(percentageJson);



  // Formate Date
  const formatDate = (timestamp) => {
    const date = new Date(timestamp * 1000);
    const day = date.getDate();
    const monthAbbreviation = new Intl.DateTimeFormat("en-US", {
      month: "short",
    }).format(date);
    const year = date.getFullYear();
    return `${day} ${monthAbbreviation} ${year}`;
  };



  const handleCheckboxChange = (itemName) => {
    setSelectedItems((prevSelectedItems) => {
      if (prevSelectedItems.includes(itemName)) {
        return prevSelectedItems.filter((item) => item !== itemName);
      } else {
        return [...prevSelectedItems, itemName];
      }
    });
  };


  const applyFilters = () => {
    setFilteredItems(selectedItems);
    setButtonClicked(false);
    const filteredRows = rows.filter((item) => {
      return (
        selectedItems.includes(item.client.name) || selectedItems.includes(item.status)
      );
    });
    onRowsFilterChange(filteredRows);
  };

  const clearSelectedTags = () => {
    setSelectedItems([]);
    setButtonClicked(false);
  };



  const [key, setKey] = useState(fullNamesJson);

  const groupSelectedItems = () => {
    const groupedItems = {
      'Full Names': [],
      Status: [],
      'ClientNames': [],
      'User Names': [],
    };

    selectedItems.forEach((item) => {
      if (fullNamesArray.includes(item)) {
        groupedItems['Full Names'].push(item);
      } else if (StatusesArray.includes(item)) {
        groupedItems.Status.push(item);
      } else if (ClientNamesArray.includes(item)) {
        groupedItems['ClientNames'].push(item);
      } else if (UserNamesArray.includes(item)) {
        groupedItems['User Names'].push(item);
      } else if (leadArray.includes(item)) {
        groupedItems['User Names'].push(item);
      }
    });

    return groupedItems;
  };


  // const desiredStatus = ["Saved"];
  // const desiredClients = ["Elite Life", "Honza's Grill"];


  const sliceWords = (str, numWords) => {
    const words = str.split(' ');
    return words.slice(0, numWords).join(' ');
  };



  const handleButtonClick = () => {
    setButtonClicked(!buttonClicked);
  }


  const renderGroupedItems = () => {
    const groupedItems = groupSelectedItems();

    
    return (
        <div className="mainTagsWrapper">
        {Object.entries(groupedItems).map(([group, items]) => (
       
            < div key={group}>
              {items.length > 0 && (
            <div className="tags-input-container">
              <ul className= {group}>
                {items.map((item, index) => (
                  <li className='mainWrapperTags tag-item-wrap' key={index}>{item}<Button variant="link" size="sm" style={{ marginLeft: '5px' }} onClick={() => handleRemoveTag(item)}><X color="#F96969" size={15} /></Button></li>
                ))}
                <Button variant="link" size="sm" style={{ marginLeft: '0px' }} onClick={() => handleRemovegroup(group)} ><X color="#F96969" size={20} /></Button>
              </ul>
            </div>
             )}
            </div>
         
        ))}
        </div>
    );
  };
  const handleRemoveTag = (itemName) => {
    setSelectedItems((prevSelectedItems) => prevSelectedItems.filter((item) => item !== itemName));
  };
  const handleRemovegroup = (groupName) => {
    setSelectedItems((prevSelectedItems) =>
      prevSelectedItems.filter((item) => {
        const groupItems = groupSelectedItems()[groupName];
        return !groupItems.includes(item);
      })
    );
  };

  return (
    <>
  <div className={`${selectClass} flexbetween paddingLR tableTopBar`}>
        {selectedRow.length === 0 ? (
          <Container fluid>
            <Row style={{ display: "flex", alignItems: "center" }}>
              <Col style={{ textAlign: "left", display: "flex", alignItems: "center" }}>
               
          
              <div className="filterDropDown">
  <Button variant="link" onClick={handleButtonClick}>
    {buttonClicked ? <Filter color='#344054' size={20} /> : <Filter color='#344054' size={20} />}
  </Button>
</div>

    <div className='filterSearch'>
    <SearchFilter  />
   </div>
      
  </Col>
  <Col>
    <div className="centerTabSales">
      <ul>
        <li>
          <NavLink to="/sales">Sales</NavLink>
        </li>
        <li>
          <NavLink to="/new" className="tabActive">
            New
          </NavLink>
        </li>
      </ul>
    </div>
  </Col>
  <Col style={{ textAlign: "right" }}>
    {salesData && salesData.length > 0 ? (
      <p className="flexEndStyle styleT3" >
        Total <span className="styleT2">{salesData.length} Sales</span>{" "}
        <strong className="styleT1">${formattedAmount}</strong>
      </p>
    ) : (
      <p className="flexEndStyle styleT3">
        Total <span className="styleT2">0 Sales</span> <strong className="styleT1">$0.00</strong>
      </p>
    )}
  </Col>
</Row>
</Container>
      ) : (
        <Container fluid>
        <Row style={{ display: "flex", alignItems: "center" }}>
          <Col style={{ textAlign: "left", display: "flex", alignItems: "center" }}>
            <span className="styleT4">Selected:{selectedRowCount}</span>
            <ul className="filterBtn">
              <li>
                <Button  variant="lostFilter">Lost
              <XCircle color="#D92D20" size={20} />
               </Button>
             
            </li>
            <li>  <Button  variant="wonFilter">Won
                <CheckCircle color="#079455" size={20} />
               </Button></li>
              <li>
            
            </li>
              <li>
                <Button variant="downloadBtn">
                <Download color="#344054" size={20} />
               </Button>
            </li>
            </ul>
          </Col>
          <Col>
            <div className="centerTabSales">
              <ul>
                <li>
                  <NavLink to="/sales">Sales</NavLink>
                </li>
                <li>
                  <NavLink to="/new" className="tabActive">
                    New <PlusLg color="#fff" size={20} />
                  </NavLink>
                </li>
              </ul>
            </div>
          </Col>
          <Col style={{ textAlign: "right" }}>
            {salesData && salesData.length > 0 ? (
              <p className="flexEndStyle styleT3">
                Total <span className="styleT2">{salesData.length} Sales</span>{" "}
                <strong className="styleT1">${formattedAmount}</strong>
              </p>
            ) : (
              <p className="flexEndStyle styleT3">
                Total <span className="styleT2">0 Sales</span> <strong className="styleT1">$0.00</strong>
              </p>
            )}
          </Col>
        </Row>
      </Container>
        )}
    </div>

{buttonClicked && (
      <Tabs
        id="controlled-tab-example"
        activeKey={key}
        onSelect={(k) => setKey(k)}
       className="filtterBoxWrapper"
      >
        <Tab eventKey="DateRange" title={<><CalendarWeek color="#667085" size={16} /> Date Range</>}>
        <ul>
      {createdDateArray.map((itemName, index) => (
        <li key={index} className={selectedItems.includes(itemName) ? 'checkedList' : ''}>
       
    
       <p>{formatDate(itemName)}</p>

        </li>
      ))}
      <Row className="buttomBottom d-flex justify-content-between align-items-center">
        <Col className="pr-2">
          <Button variant="tabContent tabCancel" onClick={clearSelectedTags}>
            Cancel
          </Button>
        </Col>
   
        <Col>
        <Button variant="tabContent tabApply" onClick={applyFilters}> 
            Apply
          </Button>
        </Col>
      </Row>
    </ul>
        </Tab>
        <Tab eventKey="Progress" title={<><BarChartSteps color="#667085" size={16} /> Progress</>}>
          <ul>
            {leadArray.map((itemName, index) => (
                <li key={index} className={selectedItems.includes(itemName.name) ? 'checkedList' : ''}>
                <label className="customCheckBox">
                 
                  <div className="userName">
                     
                    <div className="ProgressTag">
                    <div className="option" data-percentage="10">
                    <input
                    type="checkbox"
                    value={itemName}
                    checked={selectedItems.includes(itemName)}
                    onChange={() => handleCheckboxChange(itemName)}
                  />
                   <span className="checkmark">
                    <Check color="#9E77ED" size={20} />
                  </span>
                  <div className="progressWrapper">
                  <div className="labelInfo">
                    <strong>{itemName}</strong>
                    <div className="progress-light-grey">
                      <div
                        className="progress-container progress-color progress-center"
                        style={{
                          background: `linear-gradient(90deg, #9E77ED ${percentageJsonArray[index]}%, transparent ${percentageJsonArray[index]}%)`,
                        }}
                        aria-valuenow={percentageJsonArray[index]}
                        aria-valuemin="0"
                        aria-valuemax="100">
                        <span>{percentageJsonArray[index]}%</span>
                      </div>
                    </div>
                  </div>
                      <label>{percentageJsonArray[index]}%</label>
                    </div>
                      </div>
                    </div>
                  </div>
                </label>
              </li>
            ))}
               <Row className="buttomBottom d-flex justify-content-between align-items-center">
              <Col className="pr-2">
                <Button variant="tabContent tabCancel" onClick={clearSelectedTags}>
                Cancel
              </Button>
              </Col>
                <Col>
              <Button variant="tabContent tabApply" onClick={applyFilters}>
                Apply
              </Button>
              </Col>
              </Row>
          </ul>
        </Tab>
        <Tab eventKey="FullName" title={<><Person color="#667085" size={16} /> User</>}>
          <ul>
            {fullNamesArray.map((itemName, index) => (
               <li key={index} className={selectedItems.includes(itemName) ? 'checkedList' : ''}>
                <label className="customCheckBox">
                <div className="userName">
                  <img src={User01} alt="User01" />
                  {itemName} <span className="shortNameTag">@{sliceWords(itemName, 1)}</span>
                </div>
              
                  <input
                    type="checkbox"
                    value={itemName}
                    checked={selectedItems.includes(itemName)}
                    onChange={() => handleCheckboxChange(itemName)}
                  />
                 <span className="checkmark">
                  <Check color="#9E77ED" size={20} />
                </span>
                </label>
              </li>
            ))}
               <Row className="buttomBottom d-flex justify-content-between align-items-center">
              <Col className="pr-2">
                <Button variant="tabContent tabCancel" onClick={clearSelectedTags}>
                Cancel
              </Button>
              </Col>
                <Col>
              <Button variant="tabContent tabApply" onClick={applyFilters}>
                Apply
              </Button>
              </Col>
              </Row>
          </ul>
        </Tab>
       
        <Tab eventKey="ClientNames" title={<><PersonBoundingBox color="#667085" size={16} />Client</>}>
          <ul>
            {ClientNamesArray.map((itemName, index) => (
                <li key={index} className={selectedItems.includes(itemName) ? 'checkedList' : ''}>
                <label className="customCheckBox">
                <div className="userName">
                  <img src={User01} alt="User01" />
                  {itemName} <span className="shortNameTag">@{sliceWords(itemName, 1)}</span>
                </div>
              
                  <input
                    type="checkbox"
                    value={itemName}
                    checked={selectedItems.includes(itemName)}
                    onChange={() => handleCheckboxChange(itemName)}
                  />
                 <span className="checkmark">
                  <Check color="#9E77ED" size={20} />
                </span>
                </label>
              </li>
            ))}
              <Row className="buttomBottom d-flex justify-content-between align-items-center">
              <Col className="pr-2">
                <Button variant="tabContent tabCancel" onClick={clearSelectedTags}>
                Cancel
              </Button>
              </Col>
                <Col>
              <Button variant="tabContent tabApply" onClick={applyFilters}>
                Apply
              </Button>
              </Col>
              </Row>
          </ul>
        </Tab>
        <Tab eventKey="Status" title={<><ViewStacked color="#667085" size={16} />Status</>}>
          <ul>
            {StatusesArray.map((itemName, index) => (
              <li key={index} className={selectedItems.includes(itemName) ? 'checkedList' : ''}>
              <label className={`customCheckBox ${itemName}`}>
               
                <input
                  type="checkbox"
                  value={itemName}
                  onChange={() => handleCheckboxChange(itemName)}
                  checked={selectedItems.includes(itemName)}
                />
                <span className="checkmark">
                  <Check color="#9E77ED" size={20} />
                </span>
                <div className="userName">
                  <span  className="NameStatus">{itemName}</span> <span className="countStatus">{getStatusCount(itemName)}</span>
                </div>
              </label>
              </li>

            
            ))}
               <Row className="buttomBottom d-flex justify-content-between align-items-center">
              <Col className="pr-2">
                <Button variant="tabContent tabCancel" onClick={clearSelectedTags}>
                Cancel
              </Button>
              </Col>
                <Col>
              <Button variant="tabContent tabApply" onClick={applyFilters}>
                Apply
              </Button>
              </Col>
              </Row>
          </ul>
        </Tab>
       
      </Tabs>
 )} 
      {filteredItems.length > 0 && renderGroupedItems()}
</>
  );
};

export default TableTopBar;
